from flask import Flask
from prometheus_client import Counter, Histogram, generate_latest, Gauge, Summary
import time

app = Flask(__name__)

REQUEST_COUNT = Counter('requests', 'Number of requests')
LATENCY = Histogram('latency', 'Latency in seconds')
BUSINESS_METRIC = Gauge('business_metric', 'Business metric gauge for our service')
OPERATION_SUMMARY = Summary('operation_summary', 'Summary statistics of operation latency')

@app.route("/")
def home():
    BUSINESS_METRIC.inc()  # increment business gauge counter
    REQUEST_COUNT.inc()  # increment request counter
    start = time.time()
    
    # artificial delay of 0.1 seconds as mock operation latency
    time.sleep(0.1)  
    LATENCY.observe(time.time()-start)  # observe the request latency
    OPERATION_SUMMARY.observe(time.time() - start)  # observe summary statistics of operation
    
    return "Hello, World!"

@app.route('/metrics')
def metrics():
    return generate_latest(), 200, {'Content-Type': 'text/plain; charset=utf-8'}

if __name__ == "__main__":
    app.run(host="0.0.0.0", port=5000)